import{_ as t,o as i,c as a,a2 as r}from"./chunks/framework.D5wUhsuj.js";const u=JSON.parse('{"title":"Identity Providers","description":"","frontmatter":{},"headers":[],"relativePath":"admin/identity_providers.md","filePath":"admin/identity_providers.md","lastUpdated":1783546178000}'),o={name:"admin/identity_providers.md"};function n(s,e,l,d,p,c){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="identity-providers" tabindex="-1">Identity Providers <a class="header-anchor" href="#identity-providers" aria-label="Permalink to &quot;Identity Providers&quot;">​</a></h1><p>prokube uses Keycloak as the platform identity broker. External identity providers connect corporate login systems to prokube while Keycloak remains the integration point for platform groups, application clients, and tokens.</p><p>Use the Keycloak admin console only for connecting to external identity-providers such as Azure AD / Entra ID for an enterprise wide SSO setup and advanced IAM operations. Routine user, workspace, and group administration should use <a href="./user_management.html">User Management</a> when the required flow is available there.</p><h2 id="planning" tabindex="-1">Planning <a class="header-anchor" href="#planning" aria-label="Permalink to &quot;Planning&quot;">​</a></h2><p>Before adding an external provider, decide:</p><ul><li>which realm is used for prokube users;</li><li>which external domains are allowed to sign in;</li><li>which external groups or claims should map to prokube groups;</li><li>whether MFA is enforced by the external provider, Keycloak, or both;</li><li>who owns client-secret rotation and login monitoring.</li></ul><p>All redirect URIs must use HTTPS in production. Keep client secrets in the identity provider and Keycloak only; do not put them in docs, screenshots, or Git repositories.</p><h2 id="microsoft-entra-id" tabindex="-1">Microsoft Entra ID <a class="header-anchor" href="#microsoft-entra-id" aria-label="Permalink to &quot;Microsoft Entra ID&quot;">​</a></h2><p>For Microsoft Entra ID, create an application registration in the Entra admin center, then configure Keycloak as an OIDC or Microsoft identity provider.</p><p>Common configuration shape:</p><ol><li>Create an Entra application registration for prokube.</li><li>Add the Keycloak broker redirect URI shown by Keycloak for the provider.</li><li>Create a client secret and record its expiration date.</li><li>Configure the provider in Keycloak with the Entra tenant endpoints, client ID, and client secret.</li><li>Add claim or group mappers when prokube groups should be derived from Entra claims.</li><li>Test login with a non-admin user before rolling out broadly.</li></ol><p>If Entra shows <strong>Admin approval needed</strong>, the Entra tenant policy may require explicit consent. In some environments, setting the provider prompt behavior to account selection avoids a blocked silent-login path, but the correct fix depends on the tenant policy.</p><h2 id="other-oidc-providers" tabindex="-1">Other OIDC Providers <a class="header-anchor" href="#other-oidc-providers" aria-label="Permalink to &quot;Other OIDC Providers&quot;">​</a></h2><p>Google Workspace, Okta, and generic OIDC providers follow the same pattern:</p><ol><li>Create an OIDC client in the provider.</li><li>Copy the Keycloak redirect URI exactly.</li><li>Configure issuer, authorization, token, userinfo, and JWKS endpoints where Keycloak does not discover them automatically.</li><li>Request only the scopes required for identity and group mapping.</li><li>Configure mappers for email, name, groups, and any platform-specific claims.</li></ol><p>Provider consoles change frequently. Use the provider&#39;s documentation for UI-specific steps and Keycloak for the exact redirect URI and broker endpoint.</p><h2 id="group-mapping" tabindex="-1">Group Mapping <a class="header-anchor" href="#group-mapping" aria-label="Permalink to &quot;Group Mapping&quot;">​</a></h2><p>External users usually need a platform group before they can access prokube resources. Depending on the deployment, this can be assigned as a default group in Keycloak, mapped from an external claim, or managed manually after first login.</p><p>Validate group mapping with a test account:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> profiles</span></span></code></pre></div><p>If login succeeds but the user cannot access expected pages or workspaces, check the user&#39;s Keycloak groups, token claims, and workspace assignments. Users may need to sign out and sign in again after group changes so new claims appear in their session.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Check</th></tr></thead><tbody><tr><td><code>invalid redirect_uri</code></td><td>The redirect URI in the external provider must match the Keycloak broker redirect URI exactly, including path and trailing slash.</td></tr><tr><td>Login works but access is denied</td><td>Confirm the user has the required prokube group and workspace access.</td></tr><tr><td>Groups are missing</td><td>Check provider scopes, group claim names, Keycloak mappers, and whether the user refreshed their session after mapping changes.</td></tr><tr><td>Email-related login errors</td><td>Confirm the provider returns a verified email claim or configure Keycloak flow requirements appropriately.</td></tr><tr><td>Secret expired</td><td>Rotate the provider client secret in the external provider and Keycloak, then test login immediately.</td></tr></tbody></table><h2 id="security-expectations" tabindex="-1">Security Expectations <a class="header-anchor" href="#security-expectations" aria-label="Permalink to &quot;Security Expectations&quot;">​</a></h2><ul><li>Use HTTPS-only redirect URIs.</li><li>Rotate client secrets before they expire.</li><li>Request minimal scopes.</li><li>Enable login event auditing in the identity provider and Keycloak where available.</li><li>Prefer provider-enforced MFA for corporate accounts.</li><li>Keep a break-glass admin procedure for identity-provider outages.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./user_management.html">User Management</a></li><li><a href="./operations_runbooks.html#keycloak-bootstrap-and-advanced-iam">Operations Runbooks</a></li><li><a href="./application_authentication.html">Application Authentication</a></li></ul>',27)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
